/**
 * Item-ID based scroll position manager.
 *
 * Saves the ID of the first visible story item in the viewport instead of
 * pixel offset. This handles the case where new items are prepended to the
 * list (e.g., new HN stories) while the user is away — pixel-based
 * restoration would point to the wrong item.
 */
var STORAGE_KEY = 'react-hn-scroll'

/**
 * Escape a string for use in a CSS selector attribute value.
 * Prevents selector injection from untrusted sessionStorage data.
 */
function escapeSelector(str) {
  // CSS.escape is available in modern browsers; fallback for older ones
  if (typeof CSS !== 'undefined' && CSS.escape) {
    return CSS.escape(str)
  }
  // Manual escape: backslash-escape special CSS characters
  return String(str).replace(/[\\'"[\]]/g, '\\$&')
}

/**
 * Find the first story item that is visible in the viewport.
 * Looks for .ListItem elements and returns the data-id attribute of the
 * first one whose top is at or below the current scroll position.
 */
function getFirstVisibleItemId() {
  var items = document.querySelectorAll('.ListItem[data-id]')

  for (var i = 0; i < items.length; i++) {
    var rect = items[i].getBoundingClientRect()
    // Item's top is visible (between viewport top and bottom)
    if (rect.top >= 0 && rect.top < window.innerHeight) {
      return items[i].getAttribute('data-id')
    }
    // Item is partially visible at top of viewport
    if (rect.top < 0 && rect.bottom > 0) {
      // Check if next item is fully visible — prefer the one that's fully in view
      if (i + 1 < items.length) {
        var nextRect = items[i + 1].getBoundingClientRect()
        if (nextRect.top >= 0 && nextRect.top < window.innerHeight) {
          return items[i + 1].getAttribute('data-id')
        }
      }
      return items[i].getAttribute('data-id')
    }
  }

  // Fallback: return the first item if nothing is clearly visible
  if (items.length > 0) {
    return items[0].getAttribute('data-id')
  }

  return null
}

/**
 * Save the current scroll position as the ID of the first visible item.
 * @param {string} routeKey - The route identifier (e.g., 'news', 'newest')
 */
function savePosition(routeKey) {
  var itemId = getFirstVisibleItemId()
  if (itemId) {
    try {
      window.sessionStorage.setItem(STORAGE_KEY + ':' + routeKey, JSON.stringify({
        itemId: itemId,
        timestamp: Date.now()
      }))
    } catch (e) {
      // sessionStorage may be full or unavailable
    }
  }
}

/**
 * Restore scroll position to the item with the given ID.
 * Retries if the item isn't in the DOM yet (waiting for Firebase data).
 * Optionally highlights the restored item for a few seconds.
 * @param {string} routeKey - The route identifier
 * @param {Object} options - Options
 * @param {number} options.maxAttempts - Max retry attempts (default 30)
 * @param {number} options.delay - Delay between retries in ms (default 100)
 * @param {boolean} options.highlight - Whether to highlight the restored item (default true)
 * @param {number} options.highlightDuration - Highlight duration in ms (default 2500)
 * @returns {Function} cancel function - call to stop pending retries
 */
function restorePosition(routeKey, options) {
  var opts = options || {}
  var maxAttempts = opts.maxAttempts !== undefined ? opts.maxAttempts : 30
  var delay = opts.delay !== undefined ? opts.delay : 100
  var highlight = opts.highlight !== undefined ? opts.highlight : true
  var highlightDuration = opts.highlightDuration !== undefined ? opts.highlightDuration : 2600

  var cancelled = false
  var pendingTimers = []
  var highlightTimer = null

  function cancel() {
    cancelled = true
    for (var i = 0; i < pendingTimers.length; i++) {
      clearTimeout(pendingTimers[i])
    }
    pendingTimers = []
    if (highlightTimer) {
      clearTimeout(highlightTimer)
      highlightTimer = null
    }
  }

  var raw
  try {
    raw = window.sessionStorage.getItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    return cancel
  }

  if (!raw) return cancel

  var saved
  try {
    saved = JSON.parse(raw)
  } catch (e) {
    return cancel
  }

  if (!saved || !saved.itemId) return cancel

  var attempts = 0
  var escapedId = escapeSelector(saved.itemId)

  function doRestore() {
    if (cancelled) return

    var el = document.querySelector('.ListItem[data-id="' + escapedId + '"]')

    if (el) {
      // Scroll so the element is near the top of the viewport with a small offset
      var rect = el.getBoundingClientRect()
      var scrollTop = window.pageYOffset || document.documentElement.scrollTop
      var targetY = scrollTop + rect.top - 8 // 8px offset from top
      if (targetY < 0) targetY = 0
      window.scrollTo(0, targetY)

      // Highlight the restored item
      if (highlight) {
        el.classList.add('ListItem--scroll-restore')
        highlightTimer = setTimeout(function() {
          if (!cancelled) {
            el.classList.remove('ListItem--scroll-restore')
          }
        }, highlightDuration)
      }
      return
    }

    // Item not in DOM yet, retry
    attempts++
    if (attempts < maxAttempts) {
      pendingTimers.push(setTimeout(doRestore, delay))
    }
  }

  // Attempt restore immediately; retries handle timing issues
  doRestore()

  return cancel
}

/**
 * Clear saved position for a route.
 * @param {string} routeKey
 */
function clearPosition(routeKey) {
  try {
    window.sessionStorage.removeItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    // ignore
  }
}

export default {
  savePosition,
  restorePosition,
  clearPosition,
  getFirstVisibleItemId
}
